# Data models
@dataclass
class User:
    id: str
    username: str
    bio: str
    email: str
    phone: str
    address: str

@dataclass
class Post:
    id: str
    title: str
    content: str
    author_id: str

# In-memory data store (replace with database in production)
users_db: Dict[str, User] = {}
posts_db: Dict[str, Post] = {}
sessions: Dict[str, str] = {}  # session_token -> user_id

