# GraphQL Schema
type_defs = """
    type Query {
        user(id: ID!): User
        users(limit: Int = 10, offset: Int = 0): [User!]!
        post(id: ID!): Post
        posts(limit: Int = 10, offset: Int = 0): [Post!]!
        me: User
    }
    
    type User {
        id: ID!
        username: String!
        bio: String!
        email: String
        phone: String
        address: String
        posts: [Post!]!
    }
    
    type Post {
        id: ID!
        title: String!
        content: String!
        author: User!
    }
"""

# Query resolver
query = QueryType()

@query.field("user")
def resolve_user(_, info, id: str):
    # Input validation: sanitize ID
    if not id or not isinstance(id, str):
        return None
    
    # Prevent injection by ensuring ID is alphanumeric
    if not id.replace("-", "").replace("_", "").isalnum():
        return None
    
    # Limit ID length to prevent DoS
    if len(id) > 100:
        return None
    
    return users_db.get(id)

@query.field("users")
def resolve_users(_, info, limit: int = 10, offset: int = 0):
    # Input validation and rate limiting
    if not isinstance(limit, int) or not isinstance(offset, int):
        raise ValueError("Invalid pagination parameters")
    
    # Enforce maximum limits to prevent DoS
    if limit < 0 or limit > 100:
        limit = 10
    if offset < 0 or offset > 10000:
        offset = 0
    
    all_users = list(users_db.values())
    return all_users[offset:offset + limit]

@query.field("post")
def resolve_post(_, info, id: str):
    # Input validation
    if not id or not isinstance(id, str):
        return None
    
    if not id.replace("-", "").replace("_", "").isalnum():
        return None
    
    if len(id) > 100:
        return None
    
    return posts_db.get(id)

@query.field("posts")
def resolve_posts(_, info, limit: int = 10, offset: int = 0):
    # Input validation
    if not isinstance(limit, int) or not isinstance(offset, int):
        raise ValueError("Invalid pagination parameters")
    
    if limit < 0 or limit > 100:
        limit = 10
    if offset < 0 or offset > 10000:
        offset = 0
    
    all_posts = list(posts_db.values())
    return all_posts[offset:offset + limit]

@query.field("me")
def resolve_me(_, info):
    current_user = info.context.get("current_user")
    if not current_user:
        return None
    return current_user

# User type resolver
user_type = ObjectType("User")

@user_type.field("posts")
def resolve_user_posts(user, info):
    # Return posts authored by this user
    return [post for post in posts_db.values() if post.author_id == user.id]

@user_type.field("email")
def resolve_user_email(user, info):
    # Field-level authorization: only return email if viewing own profile
    current_user = info.context.get("current_user")
    if current_user and current_user.id == user.id:
        return user.email
    return None

@user_type.field("phone")
def resolve_user_phone(user, info):
    # Field-level authorization: only return phone if viewing own profile
    current_user = info.context.get("current_user")
    if current_user and current_user.id == user.id:
        return user.phone
    return None

@user_type.field("address")
def resolve_user_address(user, info):
    # Field-level authorization: only return address if viewing own profile
    current_user = info.context.get("current_user")
    if current_user and current_user.id == user.id:
        return user.address
    return None

# Post type resolver
post_type = ObjectType("Post")

@post_type.field("author")
def resolve_post_author(post, info):
    return users_db.get(post.author_id)

# Create executable schema
schema = make_executable_schema(type_defs, query, user_type, post_type)

# Flask app
app = Flask(__name__)

# Security headers middleware
@app.after_request
def add_security_headers(response):
    response.headers['X-Content-Type-Options'] = 'nosniff'
    response.headers['X-Frame-Options'] = 'DENY'
    response.headers['X-XSS-Protection'] = '1; mode=block'
    response.headers['Strict-Transport-Security'] = 'max-age=31536000; includeSubDomains'
    response.headers['Content-Security-Policy'] = "default-src 'self'"
    return response

# Authentication middleware
def get_current_user(request):
    # Extract session token from Authorization header
    auth_header = request.headers.get('Authorization', '')
    
    if not auth_header.startswith('Bearer '):
        return None
    
    token = auth_header[7:]  # Remove 'Bearer ' prefix
    
    # Validate token format
    if not token or len(token) < 32 or len(token) > 256:
        return None
    
    # Look up user by session token
    user_id = sessions.get(token)
    if not user_id:
        return None
    
    return users_db.get(user_id)

# Query depth and complexity validation
def validate_query_complexity(query_string: str) -> bool:
    # Prevent deeply nested queries (DoS protection)
    max_depth = 10
    depth = query_string.count('{')
    
    if depth > max_depth:
        return False
    
    # Limit query length
    if len(query_string) > 10000:
        return False
    
    return True

