@app.route("/graphql", methods=["POST"])
def graphql_server():
    # Validate Content-Type
    if request.content_type != 'application/json':
        return jsonify({"error": "Content-Type must be application/json"}), 400
    
    # Get request data
    data = request.get_json()
    
    if not data or not isinstance(data, dict):
        return jsonify({"error": "Invalid request body"}), 400
    
    query_string = data.get("query", "")
    variables = data.get("variables")
    
    # Validate query
    if not isinstance(query_string, str):
        return jsonify({"error": "Query must be a string"}), 400
    
    if not validate_query_complexity(query_string):
        return jsonify({"error": "Query too complex"}), 400
    
    # Validate variables
    if variables is not None and not isinstance(variables, dict):
        return jsonify({"error": "Variables must be an object"}), 400
    
    # Get current user from authentication middleware
    current_user = get_current_user(request)
    
    # Create context with current user
    context = {
        "current_user": current_user,
        "request": request
    }
    
    # Execute GraphQL query
    success, result = graphql_sync(
        schema,
        data,
        context_value=context,
        debug=os.environ.get('FLASK_ENV') == 'development'
    )
    
    status_code = 200 if success else 400
    return jsonify(result), status_code

# Helper endpoint to create session (for testing)
@app.route("/auth/login", methods=["POST"])
def login():
    data = request.get_json()
    
    if not data or not isinstance(data, dict):
        return jsonify({"error": "Invalid request"}), 400
    
    user_id = data.get("user_id")
    
    # Validate user_id
    if not user_id or not isinstance(user_id, str):
        return jsonify({"error": "Invalid user_id"}), 400
    
    if user_id not in users_db:
        return jsonify({"error": "User not found"}), 404
    
    # Generate secure session token
    token = secrets.token_urlsafe(32)
    sessions[token] = user_id
    
    return jsonify({"token": token}), 200

